args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?weapon ?label WHERE {
  VALUES ?class { wd:Q1194268 wd:Q5514406 wd:Q121245 wd:Q170515 wd:Q39851 wd:Q170511 wd:Q158179 wd:Q208373 wd:Q208810 }
  ?weapon wdt:P31 ?class .
  ?weapon rdfs:label ?label .
  FILTER(LANG(?label) = "en")
}
LIMIT 10
